using System;
using System.Linq;
using CKAN;
using CKAN.IO;
using Tests.Data;
using Tests.Core.Relationships;

static string[] Ids<TKey, TValue>(System.Collections.Generic.Dictionary<TKey, TValue> dict) where TKey : CkanModule
    => dict.Keys.Select(m => m.identifier).OrderBy(id => id).ToArray();

var modules = RelationshipResolverTests.MergeWithDefaults(
    @"{
        ""identifier"": ""InstallingMod"",
        ""recommends"": [
            { ""name"": ""RecA"" },
            { ""name"": ""RecC"" },
            { ""name"": ""RecD"" },
            { ""name"": ""RecE"" }
        ],
        ""suggests"": [
            { ""name"": ""SugA"" },
            { ""name"": ""SugC"" },
            { ""name"": ""SugD"" }
        ]
    }",
    @"{
        ""identifier"": ""ReorderedMod"",
        ""recommends"": [
            { ""name"": ""RecD"" },
            { ""name"": ""RecE"" },
            { ""name"": ""RecC"" },
            { ""name"": ""RecA"" }
        ],
        ""suggests"": [
            { ""name"": ""SugD"" },
            { ""name"": ""SugC"" },
            { ""name"": ""SugA"" }
        ]
    }",
    @"{ ""identifier"": ""RecA"" }",
    @"{
        ""identifier"": ""RecC"",
        ""conflicts"": [ { ""name"": ""RecD"" }, { ""name"": ""RecE"" } ]
    }",
    @"{
        ""identifier"": ""RecD"",
        ""conflicts"": [ { ""name"": ""RecC"" } ]
    }",
    @"{
        ""identifier"": ""RecE"",
        ""conflicts"": [ { ""name"": ""RecC"" } ]
    }",
    @"{ ""identifier"": ""SugA"" }",
    @"{
        ""identifier"": ""SugC"",
        ""conflicts"": [ { ""name"": ""SugD"" } ]
    }",
    @"{
        ""identifier"": ""SugD"",
        ""conflicts"": [ { ""name"": ""SugC"" } ]
    }").ToArray();

using var inst     = new DisposableKSP();
using var repo     = new TemporaryRepository(modules);
using var repoData = new TemporaryRepositoryData(new NullUser(), repo.repo);
using var regMgr   = RegistryManager.Instance(inst.KSP, repoData.Manager, new Repository[] { repo.repo });
var registry = regMgr.registry;

bool RunScenario(string ident)
{
    var installing = registry.LatestAvailable(ident,
                                              inst.KSP.StabilityToleranceConfig,
                                              inst.KSP.VersionCriteria())!;
    ModuleInstaller.FindRecommendations(inst.KSP,
                                        new[] { installing },
                                        new[] { installing },
                                        Array.Empty<CkanModule>(),
                                        Array.Empty<CkanModule>(),
                                        registry,
                                        out var recommendations,
                                        out var suggestions,
                                        out var supporters);

    var recIds = Ids(recommendations);
    var sugIds = Ids(suggestions);
    Console.WriteLine($"{ident} recommendations: {string.Join(", ", recIds)}");
    Console.WriteLine($"{ident} suggestions: {string.Join(", ", sugIds)}");
    Console.WriteLine($"{ident} auto-checked recommendations: {string.Join(", ", recommendations.Where(kvp => kvp.Value.Item1).Select(kvp => kvp.Key.identifier).OrderBy(id => id))}");

    var expectedRecs = new[] { "RecA", "RecC", "RecD", "RecE" };
    var expectedSugs = new[] { "SugA", "SugC", "SugD" };
    var fixedBehavior = expectedRecs.All(id => recIds.Contains(id))
                        && expectedSugs.All(id => sugIds.Contains(id));
    if (!fixedBehavior)
    {
        return false;
    }
    if (recommendations.Where(kvp => new[] { "RecC", "RecD", "RecE" }.Contains(kvp.Key.identifier))
                       .Any(kvp => kvp.Value.Item1))
    {
        Console.Error.WriteLine($"{ident}: conflicting recommendations should be listed but not auto-checked.");
        Environment.ExitCode = 2;
        return false;
    }
    return true;
}

var expectFixed = Environment.GetEnvironmentVariable("EXPECT_FIXED") == "1";
var firstFixed = RunScenario("InstallingMod");

if (!expectFixed)
{
    if (firstFixed)
    {
        Console.Error.WriteLine("Bug was not reproduced: all optional relationships were listed already.");
        return 3;
    }
    Console.WriteLine("Bug reproduced: later conflicting optional relationships were omitted.");
    return 0;
}

var secondFixed = RunScenario("ReorderedMod");
if (!firstFixed || !secondFixed)
{
    Console.Error.WriteLine("Expected all conflicting optional relationships to be listed in both orders.");
    return Environment.ExitCode == 0 ? 1 : Environment.ExitCode;
}
return 0;
